import{_ as t,a,b as d,c as s}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as i,o as l,c as n,a2 as o}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"S3 Channel شامل کریں","description":"","frontmatter":{},"headers":[],"relativePath":"ur/upload/s3.md","filePath":"ur/upload/s3.md","lastUpdated":1781962217000}'),c={name:"ur/upload/s3.md"};function r(p,e,h,u,m,b){return l(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="s3-channel-شامل-کریں" tabindex="-1">S3 Channel شامل کریں <a class="header-anchor" href="#s3-channel-شامل-کریں" aria-label="Permalink to &quot;S3 Channel شامل کریں&quot;">​</a></h1><h2 id="کب-استعمال-کریں" tabindex="-1">کب استعمال کریں <a class="header-anchor" href="#کب-استعمال-کریں" aria-label="Permalink to &quot;کب استعمال کریں&quot;">​</a></h2><p>S3 channel اس وقت استعمال کریں جب:</p><ul><li>آپ کوئی بھی S3-compatible object storage service connect کرنا چاہتے ہیں، جیسے Cloudflare R2، Backblaze B2، MinIO، AWS S3، یا کوئی اور compatible provider۔</li><li>آپ standard S3 configuration model پسند کرتے ہیں: <code>Endpoint</code>، Access Key، اور Secret Key۔</li><li>آپ native Cloudflare R2 binding channel استعمال نہیں کرنا چاہتے، یا آپ کا storage provider Cloudflare R2 نہیں ہے۔</li></ul><h2 id="شروع-کرنے-سے-پہلے-کیا-چاہیے" tabindex="-1">شروع کرنے سے پہلے کیا چاہیے <a class="header-anchor" href="#شروع-کرنے-سے-پہلے-کیا-چاہیے" aria-label="Permalink to &quot;شروع کرنے سے پہلے کیا چاہیے&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ضرورت</th><th>مقصد</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>object storage service کا S3 API endpoint۔</td></tr><tr><td>Bucket name</td><td>وہ bucket جہاں files محفوظ ہوں گی۔</td></tr><tr><td>Region</td><td>storage region۔ Cloudflare R2 کے لیے عموماً <code>auto</code> ہوتا ہے۔</td></tr><tr><td>Access Key ID</td><td>S3 access key ID۔</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key۔</td></tr><tr><td>CDN domain</td><td>file access کے لیے optional custom domain۔</td></tr></tbody></table><p>Cloudflare R2 کو S3 API کے ذریعے استعمال کرنے کی مثال:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://your-account-id.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: your-r2-bucket-name</span></span>
<span class="line"><span>Region: auto</span></span>
<span class="line"><span>Access Key ID: copied from the Cloudflare R2 API token</span></span>
<span class="line"><span>Secret Access Key: copied from the Cloudflare R2 API token</span></span></code></pre></div><h2 id="کہاں-شامل-کریں" tabindex="-1">کہاں شامل کریں <a class="header-anchor" href="#کہاں-شامل-کریں" aria-label="Permalink to &quot;کہاں شامل کریں&quot;">​</a></h2><ol><li>System Settings کھولیں۔</li><li>Upload Settings میں جائیں۔</li><li>اوپر دائیں طرف Add Channel پر کلک کریں۔</li><li><code>S3</code> منتخب کریں۔</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>کام</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>اس S3 channel کا واضح نام، مثلاً <code>s3test</code> یا <code>R2-S3</code>۔</td><td>Yes</td></tr><tr><td>Enable channel</td><td>یہ کنٹرول کرتا ہے کہ channel upload selection میں شامل ہو یا نہیں۔</td><td>Recommended</td></tr><tr><td>Endpoint</td><td>مکمل S3 service endpoint، <code>https://</code> سمیت۔</td><td>Yes</td></tr><tr><td>Custom CDN domain</td><td>Optional۔ set ہونے پر generated file links اس domain کو ترجیح دیتے ہیں۔</td><td>No</td></tr><tr><td>Bucket name</td><td>bucket name، مثلاً <code>s3test</code> یا <code>img-r2</code>۔</td><td>Yes</td></tr><tr><td>Bucket region</td><td>Region۔ Cloudflare R2 کے لیے عموماً <code>auto</code>۔</td><td>Yes</td></tr><tr><td>Access Key ID</td><td>S3 access key ID۔</td><td>Yes</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key۔</td><td>Yes</td></tr><tr><td>Path-style access</td><td>compatibility switch۔ default off ہے۔ کچھ MinIO، OpenList، یا self-hosted S3 services کو اس کی ضرورت ہو سکتی ہے۔</td><td>No</td></tr><tr><td>Quota limit</td><td>capacity کی بنیاد پر S3 channel کو upload selection میں شامل یا خارج کرنے کے لیے۔</td><td>No</td></tr><tr><td>Capacity limit</td><td>quota limit enabled ہونے کے بعد required، مثلاً <code>10 GB</code>۔</td><td>Required when quota limit is enabled</td></tr><tr><td>Threshold</td><td>usage اس percentage تک پہنچنے کے بعد لکھنا روک دیتا ہے، مثلاً <code>90%</code>۔</td><td>Required when quota limit is enabled</td></tr><tr><td>Remark</td><td>اپنی maintenance کے لیے notes۔</td><td>No</td></tr></tbody></table><h2 id="cloudflare-r2-s3-api-keys-بنائیں" tabindex="-1">Cloudflare R2 S3 API Keys بنائیں <a class="header-anchor" href="#cloudflare-r2-s3-api-keys-بنائیں" aria-label="Permalink to &quot;Cloudflare R2 S3 API Keys بنائیں&quot;">​</a></h2><ol><li>Cloudflare Dashboard کھولیں۔</li><li><code>R2 Object Storage</code> میں جائیں۔</li><li><code>Manage R2 API Tokens</code> یا API token management entry تلاش کریں۔</li></ol><p>![R2 API token entry](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>ایسا R2 API token بنائیں جو target bucket تک access رکھتا ہو۔</li></ol><p><img src="`+t+'" alt="Create an account API token" loading="lazy"></p><ol start="5"><li>generated <code>Access Key ID</code> اور <code>Secret Access Key</code> copy کریں۔</li></ol><p><img src="'+a+'" alt="Copy the token values" loading="lazy"></p><ol start="6"><li>R2 bucket page پر واپس جا کر bucket name confirm کریں۔</li><li>account کا S3 API endpoint note کریں۔ یہ عموماً ایسا ہوتا ہے:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-account-id.r2.cloudflarestorage.com</span></span></code></pre></div><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Upload Settings کھولیں۔</li><li>Add Channel پر کلک کریں۔</li><li><code>S3</code> منتخب کریں۔</li><li>قابل شناخت channel name درج کریں، مثلاً <code>s3test</code>۔</li><li><code>Endpoint</code> میں S3 API endpoint درج کریں۔</li><li>اگر custom CDN استعمال کرتے ہیں تو <code>Custom CDN domain</code> میں درج کریں، ورنہ خالی چھوڑ دیں۔</li><li>bucket name درج کریں۔</li><li>region درج کریں۔ Cloudflare R2 example کے لیے <code>auto</code> استعمال کریں۔</li><li>Access Key ID اور Secret Access Key درج کریں۔</li><li>path-style access کو off رہنے دیں، جب تک provider واضح طور پر require نہ کرے۔</li><li>capacity control چاہیے تو quota limit enable کریں اور capacity limit / threshold درج کریں۔</li><li>Save پر کلک کریں۔</li></ol><p><img src="'+d+'" alt="Add S3 configuration" loading="lazy"></p><h2 id="verify-کیسے-کریں" tabindex="-1">Verify کیسے کریں <a class="header-anchor" href="#verify-کیسے-کریں" aria-label="Permalink to &quot;Verify کیسے کریں&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Verify کرنے کا طریقہ</th></tr></thead><tbody><tr><td>Channel card appears</td><td>Save کے بعد Upload Settings میں S3 channel card دکھائی دینا چاہیے۔</td></tr><tr><td>Channel is enabled</td><td>card کے اوپر دائیں switch کو on رہنا چاہیے۔</td></tr><tr><td>Key fields are saved</td><td>detail view میں Endpoint، Bucket، Region، path-style access، اور متعلقہ fields دکھنے چاہئیں۔</td></tr><tr><td>Upload works</td><td>test image upload کریں اور confirm کریں کہ object target bucket میں آیا ہے۔</td></tr><tr><td>Link opens</td><td>upload کے بعد returned image link عام طور پر کھلنا چاہیے۔</td></tr><tr><td>Capacity display works</td><td>quota limit enabled ہو تو card used capacity اور configured limit دکھائے۔</td></tr></tbody></table><p>S3 capacity statistics provider bucket کو real time query کر کے نہیں بلکہ ImgBed کے local file records سے calculate ہوتے ہیں۔ S3 configuration save کرنے کے بعد system current D1 records سے quota ledger دوبارہ calculate کرتا ہے۔</p><p><img src="'+s+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="کیا-path-style-access-enable-کرنا-چاہیے؟" tabindex="-1">کیا path-style access enable کرنا چاہیے؟ <a class="header-anchor" href="#کیا-path-style-access-enable-کرنا-چاہیے؟" aria-label="Permalink to &quot;کیا path-style access enable کرنا چاہیے؟&quot;">​</a></h3><p>عام طور پر نہیں۔</p><p>صرف اس وقت enable کریں جب آپ کا S3-compatible provider virtual-hosted-style URLs support نہ کرے، یا provider documentation واضح طور پر path-style access require کرے۔ کچھ MinIO، self-hosted S3، اور OpenList-compatible endpoints کو یہ چاہیے ہو سکتا ہے۔</p><h3 id="cdn-domain-کس-لیے-ہے؟" tabindex="-1">CDN domain کس لیے ہے؟ <a class="header-anchor" href="#cdn-domain-کس-لیے-ہے؟" aria-label="Permalink to &quot;CDN domain کس لیے ہے؟&quot;">​</a></h3><p>اگر آپ bucket کے آگے CDN یا custom access domain رکھتے ہیں تو اسے یہاں درج کریں۔</p><p>configuration کے بعد generated file links اس domain کو ترجیح دیں گے۔ اگر CDN استعمال نہیں کر رہے تو field خالی چھوڑ دیں۔</p><h3 id="upload-کیوں-fail-ہوتا-ہے؟" tabindex="-1">upload کیوں fail ہوتا ہے؟ <a class="header-anchor" href="#upload-کیوں-fail-ہوتا-ہے؟" aria-label="Permalink to &quot;upload کیوں fail ہوتا ہے؟&quot;">​</a></h3><p>سب سے پہلے یہ items چیک کریں:</p><ol><li>Endpoint مکمل <code>https://</code> URL کے ساتھ ہے۔</li><li>bucket name درست ہے۔</li><li>Region provider requirement کے مطابق ہے۔</li><li>Access Key ID اور Secret Access Key مکمل copy کیے گئے ہیں۔</li><li>key کو target bucket پر write permission ہے۔</li><li>provider کو path-style access کی ضرورت نہیں، یا ضرورت ہو تو path-style access enabled ہے۔</li></ol><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>S3 Endpoint, Bucket, Region, Access Key, اور Secret Key تیار کریں</span></span>
<span class="line"><span>-&gt; Upload Settings کھولیں</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; S3 منتخب کریں</span></span>
<span class="line"><span>-&gt; Endpoint / Bucket / Region / Access Key / Secret Key درج کریں</span></span>
<span class="line"><span>-&gt; ضرورت ہو تو CDN domain درج کریں</span></span>
<span class="line"><span>-&gt; default طور پر path-style access off رہنے دیں</span></span>
<span class="line"><span>-&gt; ضرورت ہو تو quota limit enable کریں</span></span>
<span class="line"><span>-&gt; Save کریں</span></span>
<span class="line"><span>-&gt; test image upload کر کے نتیجہ چیک کریں</span></span></code></pre></div>`,40)])])}const k=i(c,[["render",r]]);export{y as __pageData,k as default};
